import React, { useState, useCallback, useMemo, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/SupabaseContext';
import { useToast } from '../components/ui/Toast';
import {
  useJobApplications,
  type JobApplication,
  type JobApplicationStatus,
  type JobApplicationUpdate,
} from '../hooks/useJobApplications';

/* ------------------------------------------------------------------ */
/*  Constants                                                          */
/* ------------------------------------------------------------------ */

const STATUS_COLUMNS: { key: JobApplicationStatus; label: string; icon: string; color: string }[] = [
  { key: 'saved', label: 'Saved', icon: 'fa-bookmark', color: '#8b949e' },
  { key: 'applied', label: 'Applied', icon: 'fa-paper-plane', color: '#7B9AB4' },
  { key: 'screening', label: 'Screening', icon: 'fa-magnifying-glass', color: '#a78bfa' },
  { key: 'interviewing', label: 'Interviewing', icon: 'fa-comments', color: '#f59e0b' },
  { key: 'offer', label: 'Offer', icon: 'fa-trophy', color: '#10b981' },
  { key: 'rejected', label: 'Rejected', icon: 'fa-circle-xmark', color: '#ef4444' },
];

const ALL_STATUSES: JobApplicationStatus[] = [
  'saved', 'applied', 'screening', 'interviewing', 'offer', 'rejected', 'withdrawn',
];

const REMOTE_OPTIONS = [
  { value: '', label: 'Not specified' },
  { value: 'remote', label: 'Remote' },
  { value: 'hybrid', label: 'Hybrid' },
  { value: 'onsite', label: 'On-site' },
];

type ViewMode = 'kanban' | 'list';
type SortField = 'updated_at' | 'company' | 'status' | 'created_at';

/* ------------------------------------------------------------------ */
/*  Helper: format salary range                                        */
/* ------------------------------------------------------------------ */

function formatSalary(min: number | null, max: number | null, currency: string): string {
  if (!min && !max) return '';
  const fmt = (n: number) => {
    if (n >= 1000) return `${Math.round(n / 1000)}k`;
    return String(n);
  };
  const sym = currency === 'USD' ? '$' : currency;
  if (min && max) return `${sym}${fmt(min)}-${sym}${fmt(max)}`;
  if (min) return `${sym}${fmt(min)}+`;
  return `up to ${sym}${fmt(max!)}`;
}

/* ------------------------------------------------------------------ */
/*  Helper: next relevant date for a card                              */
/* ------------------------------------------------------------------ */

function getNextDate(app: JobApplication): { label: string; date: string } | null {
  const now = new Date().toISOString();
  const candidates: { label: string; date: string }[] = [];

  if (app.date_deadline) candidates.push({ label: 'Deadline', date: app.date_deadline });
  if (app.date_interview) candidates.push({ label: 'Interview', date: app.date_interview });
  if (app.date_follow_up) candidates.push({ label: 'Follow-up', date: app.date_follow_up });
  if (app.date_offer) candidates.push({ label: 'Offer', date: app.date_offer });

  // Show the nearest future date, or the most recent past date
  const future = candidates.filter(c => c.date >= now).sort((a, b) => a.date.localeCompare(b.date));
  if (future.length) return future[0];

  const past = candidates.sort((a, b) => b.date.localeCompare(a.date));
  return past[0] || null;
}

/* ------------------------------------------------------------------ */
/*  Empty form state                                                   */
/* ------------------------------------------------------------------ */

interface FormData {
  company: string;
  role: string;
  status: JobApplicationStatus;
  job_url: string;
  salary_min: string;
  salary_max: string;
  salary_currency: string;
  location: string;
  remote_type: string;
  contact_name: string;
  contact_email: string;
  contact_title: string;
  date_applied: string;
  date_deadline: string;
  date_interview: string;
  date_offer: string;
  date_follow_up: string;
  notes: string;
  tags: string;
}

function emptyForm(status?: JobApplicationStatus): FormData {
  return {
    company: '',
    role: '',
    status: status || 'saved',
    job_url: '',
    salary_min: '',
    salary_max: '',
    salary_currency: 'USD',
    location: '',
    remote_type: '',
    contact_name: '',
    contact_email: '',
    contact_title: '',
    date_applied: '',
    date_deadline: '',
    date_interview: '',
    date_offer: '',
    date_follow_up: '',
    notes: '',
    tags: '',
  };
}

function appToForm(app: JobApplication): FormData {
  return {
    company: app.company,
    role: app.role,
    status: app.status,
    job_url: app.job_url || '',
    salary_min: app.salary_min != null ? String(app.salary_min) : '',
    salary_max: app.salary_max != null ? String(app.salary_max) : '',
    salary_currency: app.salary_currency || 'USD',
    location: app.location || '',
    remote_type: app.remote_type || '',
    contact_name: app.contact_name || '',
    contact_email: app.contact_email || '',
    contact_title: app.contact_title || '',
    date_applied: app.date_applied ? app.date_applied.slice(0, 10) : '',
    date_deadline: app.date_deadline ? app.date_deadline.slice(0, 10) : '',
    date_interview: app.date_interview ? app.date_interview.slice(0, 10) : '',
    date_offer: app.date_offer ? app.date_offer.slice(0, 10) : '',
    date_follow_up: app.date_follow_up ? app.date_follow_up.slice(0, 10) : '',
    notes: app.notes || '',
    tags: (app.tags || []).join(', '),
  };
}

function formToPayload(form: FormData): Record<string, unknown> {
  return {
    company: form.company.trim(),
    role: form.role.trim(),
    status: form.status,
    job_url: form.job_url.trim() || null,
    salary_min: form.salary_min ? parseInt(form.salary_min, 10) : null,
    salary_max: form.salary_max ? parseInt(form.salary_max, 10) : null,
    salary_currency: form.salary_currency || 'USD',
    location: form.location.trim() || null,
    remote_type: form.remote_type || null,
    contact_name: form.contact_name.trim() || null,
    contact_email: form.contact_email.trim() || null,
    contact_title: form.contact_title.trim() || null,
    date_applied: form.date_applied || null,
    date_deadline: form.date_deadline || null,
    date_interview: form.date_interview || null,
    date_offer: form.date_offer || null,
    date_follow_up: form.date_follow_up || null,
    notes: form.notes.trim() || null,
    tags: form.tags
      .split(',')
      .map(t => t.trim())
      .filter(Boolean),
  };
}

/* ================================================================== */
/*  Main component                                                     */
/* ================================================================== */

export default function JobTrackerPage() {
  const { user, isLoading: authLoading } = useAuth();
  const navigate = useNavigate();
  const { showToast } = useToast();
  const {
    applications,
    addApplication,
    updateApplication,
    deleteApplication,
    getByStatus,
    isLoading,
  } = useJobApplications();

  // View state
  const [viewMode, setViewMode] = useState<ViewMode>('kanban');
  const [searchQuery, setSearchQuery] = useState('');
  const [sortField, setSortField] = useState<SortField>('updated_at');
  const [sortAsc, setSortAsc] = useState(false);

  // Modal / editing state
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingApp, setEditingApp] = useState<JobApplication | null>(null);
  const [form, setForm] = useState<FormData>(emptyForm());
  const [saving, setSaving] = useState(false);
  const [confirmDelete, setConfirmDelete] = useState<string | null>(null);

  // Drag state
  const dragItemRef = useRef<string | null>(null);
  const [dragOverCol, setDragOverCol] = useState<string | null>(null);

  // Redirect if not logged in
  React.useEffect(() => {
    if (!authLoading && !user) navigate('/login');
  }, [authLoading, user, navigate]);

  /* ---------------------------------------------------------------- */
  /*  Filtering & sorting                                              */
  /* ---------------------------------------------------------------- */

  const filtered = useMemo(() => {
    let items = [...applications];
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      items = items.filter(
        app =>
          app.company.toLowerCase().includes(q) ||
          app.role.toLowerCase().includes(q) ||
          (app.location || '').toLowerCase().includes(q) ||
          (app.tags || []).some(t => t.toLowerCase().includes(q)),
      );
    }
    return items;
  }, [applications, searchQuery]);

  const sorted = useMemo(() => {
    const items = [...filtered];
    items.sort((a, b) => {
      let cmp = 0;
      switch (sortField) {
        case 'company':
          cmp = a.company.localeCompare(b.company);
          break;
        case 'status':
          cmp = ALL_STATUSES.indexOf(a.status) - ALL_STATUSES.indexOf(b.status);
          break;
        case 'created_at':
          cmp = a.created_at.localeCompare(b.created_at);
          break;
        default:
          cmp = a.updated_at.localeCompare(b.updated_at);
      }
      return sortAsc ? cmp : -cmp;
    });
    return items;
  }, [filtered, sortField, sortAsc]);

  /* ---------------------------------------------------------------- */
  /*  Handlers                                                         */
  /* ---------------------------------------------------------------- */

  const openAdd = useCallback((status?: JobApplicationStatus) => {
    setForm(emptyForm(status));
    setEditingApp(null);
    setShowAddModal(true);
  }, []);

  const openEdit = useCallback((app: JobApplication) => {
    setForm(appToForm(app));
    setEditingApp(app);
    setShowAddModal(true);
  }, []);

  const closeModal = useCallback(() => {
    setShowAddModal(false);
    setEditingApp(null);
    setForm(emptyForm());
  }, []);

  const handleSave = useCallback(async () => {
    if (!form.company.trim() || !form.role.trim()) {
      showToast('Company and role are required', true);
      return;
    }
    setSaving(true);
    try {
      const payload = formToPayload(form);
      if (editingApp) {
        const result = await updateApplication(editingApp.id, payload as JobApplicationUpdate);
        if (result) showToast('Application updated');
        else showToast('Failed to update', true);
      } else {
        const result = await addApplication(payload as { company: string; role: string });
        if (result) showToast('Application added');
        else showToast('Failed to add', true);
      }
      closeModal();
    } finally {
      setSaving(false);
    }
  }, [form, editingApp, addApplication, updateApplication, closeModal, showToast]);

  const handleDelete = useCallback(
    async (id: string) => {
      const ok = await deleteApplication(id);
      if (ok) {
        showToast('Application deleted');
        if (editingApp?.id === id) closeModal();
      } else {
        showToast('Failed to delete', true);
      }
      setConfirmDelete(null);
    },
    [deleteApplication, editingApp, closeModal, showToast],
  );

  const handleStatusChange = useCallback(
    async (id: string, newStatus: JobApplicationStatus) => {
      const result = await updateApplication(id, { status: newStatus });
      if (result) showToast(`Moved to ${newStatus}`);
    },
    [updateApplication, showToast],
  );

  /* ---------------------------------------------------------------- */
  /*  Drag & Drop handlers                                             */
  /* ---------------------------------------------------------------- */

  const onDragStart = useCallback((e: React.DragEvent, appId: string) => {
    dragItemRef.current = appId;
    e.dataTransfer.effectAllowed = 'move';
    // Add a slight delay for the drag image
    const target = e.currentTarget as HTMLElement;
    target.style.opacity = '0.5';
  }, []);

  const onDragEnd = useCallback((e: React.DragEvent) => {
    const target = e.currentTarget as HTMLElement;
    target.style.opacity = '1';
    dragItemRef.current = null;
    setDragOverCol(null);
  }, []);

  const onDragOver = useCallback((e: React.DragEvent, colKey: string) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    setDragOverCol(colKey);
  }, []);

  const onDragLeave = useCallback(() => {
    setDragOverCol(null);
  }, []);

  const onDrop = useCallback(
    (e: React.DragEvent, targetStatus: JobApplicationStatus) => {
      e.preventDefault();
      setDragOverCol(null);
      const appId = dragItemRef.current;
      if (!appId) return;

      const app = applications.find(a => a.id === appId);
      if (app && app.status !== targetStatus) {
        handleStatusChange(appId, targetStatus);
      }
      dragItemRef.current = null;
    },
    [applications, handleStatusChange],
  );

  /* ---------------------------------------------------------------- */
  /*  Form field updater                                               */
  /* ---------------------------------------------------------------- */

  const setField = useCallback(
    (field: keyof FormData) => (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
      setForm(prev => ({ ...prev, [field]: e.target.value }));
    },
    [],
  );

  /* ---------------------------------------------------------------- */
  /*  Loading state                                                    */
  /* ---------------------------------------------------------------- */

  if (authLoading || isLoading) {
    return (
      <div style={{ textAlign: 'center', padding: '4rem', color: 'var(--text-secondary)' }}>
        <i className="fa-solid fa-spinner fa-spin" style={{ marginRight: '0.5rem' }} />
        Loading...
      </div>
    );
  }

  /* ================================================================ */
  /*  Render                                                           */
  /* ================================================================ */

  return (
    <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '2rem 1.5rem' }}>
      {/* ---- Header ---- */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1.5rem', flexWrap: 'wrap', gap: '1rem' }}>
        <div>
          <h1 style={{ fontSize: '1.5rem', margin: 0, color: 'var(--text-primary)' }}>Job Tracker</h1>
          <p style={{ margin: '0.25rem 0 0', fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
            {applications.length} application{applications.length !== 1 ? 's' : ''} tracked
          </p>
        </div>

        <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center', flexWrap: 'wrap' }}>
          <input
            type="text"
            value={searchQuery}
            onChange={e => setSearchQuery(e.target.value)}
            placeholder="Search..."
            style={{ width: '180px' }}
          />

          {/* View toggle */}
          <div style={{ display: 'flex', gap: '0.25rem' }}>
            <button
              className={`btn ${viewMode === 'kanban' ? 'secondary-btn' : 'ghost-btn'}`}
              onClick={() => setViewMode('kanban')}
              title="Kanban view"
              style={{ padding: '0.4rem 0.6rem', fontSize: '0.8rem' }}
            >
              <i className="fa-solid fa-columns" />
            </button>
            <button
              className={`btn ${viewMode === 'list' ? 'secondary-btn' : 'ghost-btn'}`}
              onClick={() => setViewMode('list')}
              title="List view"
              style={{ padding: '0.4rem 0.6rem', fontSize: '0.8rem' }}
            >
              <i className="fa-solid fa-list" />
            </button>
          </div>

          <button className="btn secondary-btn large-action-btn" onClick={() => openAdd()}>
            <i className="fa-solid fa-plus" style={{ marginRight: '0.35rem' }} />
            Add Application
          </button>
        </div>
      </div>

      {/* ---- Kanban View ---- */}
      {viewMode === 'kanban' && (
        <div className="kanban-board" style={{ display: 'flex', gap: '0.75rem', overflowX: 'auto', minHeight: '400px', paddingBottom: '1rem' }}>
          {STATUS_COLUMNS.map(col => {
            const items = filtered.filter(app => app.status === col.key);
            const isOver = dragOverCol === col.key;
            return (
              <div
                key={col.key}
                className="kanban-column glass-panel"
                style={{
                  flex: '1 0 220px',
                  minWidth: '220px',
                  padding: '0.75rem',
                  display: 'flex',
                  flexDirection: 'column',
                  transition: 'box-shadow 0.15s ease',
                  boxShadow: isOver ? `inset 0 0 0 2px ${col.color}` : undefined,
                }}
                onDragOver={e => onDragOver(e, col.key)}
                onDragLeave={onDragLeave}
                onDrop={e => onDrop(e, col.key)}
              >
                {/* Column header */}
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', marginBottom: '0.75rem', paddingBottom: '0.5rem', borderBottom: `2px solid ${col.color}` }}>
                  <i className={`fa-solid ${col.icon}`} style={{ color: col.color, fontSize: '0.8rem' }} />
                  <span style={{ fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-primary)' }}>{col.label}</span>
                  <span style={{ fontSize: '0.7rem', color: 'var(--text-secondary)', marginLeft: 'auto' }}>{items.length}</span>
                </div>

                {/* Cards */}
                <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '0.4rem', overflowY: 'auto' }}>
                  {items.map(app => {
                    const salaryStr = formatSalary(app.salary_min, app.salary_max, app.salary_currency);
                    const nextDate = getNextDate(app);
                    return (
                      <div
                        key={app.id}
                        className="asym-card"
                        draggable
                        onDragStart={e => onDragStart(e, app.id)}
                        onDragEnd={onDragEnd}
                        style={{ padding: '0.6rem', cursor: 'grab' }}
                        onClick={() => openEdit(app)}
                      >
                        {/* Company & role */}
                        <div style={{ fontWeight: 600, fontSize: '0.8rem', color: 'var(--text-primary)', marginBottom: '0.15rem' }}>
                          {app.company}
                        </div>
                        <div style={{ fontSize: '0.72rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                          {app.role}
                        </div>

                        {/* Salary + location row */}
                        {(salaryStr || app.location) && (
                          <div style={{ display: 'flex', gap: '0.4rem', flexWrap: 'wrap', fontSize: '0.68rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                            {salaryStr && (
                              <span style={{ color: '#10b981' }}>
                                <i className="fa-solid fa-dollar-sign" style={{ marginRight: '0.15rem' }} />
                                {salaryStr}
                              </span>
                            )}
                            {app.location && (
                              <span>
                                <i className="fa-solid fa-location-dot" style={{ marginRight: '0.15rem' }} />
                                {app.location}
                              </span>
                            )}
                          </div>
                        )}

                        {/* Next date */}
                        {nextDate && (
                          <div style={{ fontSize: '0.68rem', color: '#f59e0b', marginBottom: '0.3rem' }}>
                            <i className="fa-solid fa-calendar" style={{ marginRight: '0.2rem' }} />
                            {nextDate.label}: {new Date(nextDate.date).toLocaleDateString()}
                          </div>
                        )}

                        {/* Tags */}
                        {app.tags && app.tags.length > 0 && (
                          <div style={{ display: 'flex', gap: '0.2rem', flexWrap: 'wrap', marginBottom: '0.3rem' }}>
                            {app.tags.slice(0, 3).map(tag => (
                              <span
                                key={tag}
                                className="small-btn"
                                style={{ fontSize: '0.6rem', padding: '0.1rem 0.3rem' }}
                              >
                                {tag}
                              </span>
                            ))}
                            {app.tags.length > 3 && (
                              <span style={{ fontSize: '0.6rem', color: 'var(--text-secondary)' }}>
                                +{app.tags.length - 3}
                              </span>
                            )}
                          </div>
                        )}

                        {/* Quick status buttons */}
                        <div style={{ display: 'flex', gap: '0.25rem', marginTop: '0.2rem', flexWrap: 'wrap' }}>
                          {STATUS_COLUMNS.filter(c => c.key !== col.key).slice(0, 4).map(c => (
                            <button
                              key={c.key}
                              onClick={e => {
                                e.stopPropagation();
                                handleStatusChange(app.id, c.key);
                              }}
                              title={`Move to ${c.label}`}
                              className="small-btn"
                              style={{
                                padding: '0.15rem 0.35rem',
                                background: `${c.color}20`,
                                color: c.color,
                                fontSize: '0.6rem',
                                border: 'none',
                              }}
                            >
                              <i className={`fa-solid ${c.icon}`} />
                            </button>
                          ))}
                        </div>
                      </div>
                    );
                  })}

                  {items.length === 0 && (
                    <div
                      style={{ textAlign: 'center', padding: '1.5rem 0.5rem', color: 'var(--text-secondary)', fontSize: '0.75rem', opacity: 0.6 }}
                    >
                      <i className="fa-solid fa-inbox" style={{ display: 'block', fontSize: '1.2rem', marginBottom: '0.4rem' }} />
                      No applications
                    </div>
                  )}

                  {/* Add button at bottom of column */}
                  <button
                    className="btn ghost-btn"
                    onClick={() => openAdd(col.key)}
                    style={{ marginTop: '0.25rem', fontSize: '0.72rem', padding: '0.35rem', width: '100%' }}
                  >
                    <i className="fa-solid fa-plus" style={{ marginRight: '0.25rem' }} />
                    Add
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* ---- List View ---- */}
      {viewMode === 'list' && (
        <div className="glass-panel" style={{ padding: '0.75rem', overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.82rem' }}>
            <thead>
              <tr style={{ borderBottom: '1px solid var(--border-color, rgba(255,255,255,0.08))' }}>
                {[
                  { field: 'company' as SortField, label: 'Company / Role' },
                  { field: 'status' as SortField, label: 'Status' },
                  { field: 'updated_at' as SortField, label: 'Updated' },
                  { field: 'created_at' as SortField, label: 'Created' },
                ].map(col => (
                  <th
                    key={col.field}
                    onClick={() => {
                      if (sortField === col.field) setSortAsc(!sortAsc);
                      else {
                        setSortField(col.field);
                        setSortAsc(false);
                      }
                    }}
                    style={{
                      textAlign: 'left',
                      padding: '0.6rem 0.75rem',
                      color: 'var(--text-secondary)',
                      fontWeight: 600,
                      cursor: 'pointer',
                      whiteSpace: 'nowrap',
                      userSelect: 'none',
                    }}
                  >
                    {col.label}
                    {sortField === col.field && (
                      <i
                        className={`fa-solid fa-caret-${sortAsc ? 'up' : 'down'}`}
                        style={{ marginLeft: '0.3rem', fontSize: '0.7rem' }}
                      />
                    )}
                  </th>
                ))}
                <th style={{ textAlign: 'left', padding: '0.6rem 0.75rem', color: 'var(--text-secondary)', fontWeight: 600 }}>
                  Salary
                </th>
                <th style={{ textAlign: 'left', padding: '0.6rem 0.75rem', color: 'var(--text-secondary)', fontWeight: 600 }}>
                  Location
                </th>
                <th style={{ padding: '0.6rem 0.75rem', width: '60px' }}></th>
              </tr>
            </thead>
            <tbody>
              {sorted.length === 0 && (
                <tr>
                  <td colSpan={7} style={{ textAlign: 'center', padding: '2rem', color: 'var(--text-secondary)' }}>
                    No applications found.
                  </td>
                </tr>
              )}
              {sorted.map(app => {
                const statusCol = STATUS_COLUMNS.find(c => c.key === app.status);
                const salaryStr = formatSalary(app.salary_min, app.salary_max, app.salary_currency);
                return (
                  <tr
                    key={app.id}
                    onClick={() => openEdit(app)}
                    style={{
                      borderBottom: '1px solid var(--border-color, rgba(255,255,255,0.05))',
                      cursor: 'pointer',
                    }}
                  >
                    <td style={{ padding: '0.6rem 0.75rem' }}>
                      <div style={{ fontWeight: 600, color: 'var(--text-primary)' }}>{app.company}</div>
                      <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>{app.role}</div>
                    </td>
                    <td style={{ padding: '0.6rem 0.75rem' }}>
                      {statusCol && (
                        <span
                          className="small-btn"
                          style={{ background: `${statusCol.color}20`, color: statusCol.color, border: 'none', fontSize: '0.7rem' }}
                        >
                          <i className={`fa-solid ${statusCol.icon}`} style={{ marginRight: '0.25rem' }} />
                          {statusCol.label}
                        </span>
                      )}
                    </td>
                    <td style={{ padding: '0.6rem 0.75rem', color: 'var(--text-secondary)', fontSize: '0.78rem', whiteSpace: 'nowrap' }}>
                      {new Date(app.updated_at).toLocaleDateString()}
                    </td>
                    <td style={{ padding: '0.6rem 0.75rem', color: 'var(--text-secondary)', fontSize: '0.78rem', whiteSpace: 'nowrap' }}>
                      {new Date(app.created_at).toLocaleDateString()}
                    </td>
                    <td style={{ padding: '0.6rem 0.75rem', color: salaryStr ? '#10b981' : 'var(--text-secondary)', fontSize: '0.78rem', whiteSpace: 'nowrap' }}>
                      {salaryStr || '-'}
                    </td>
                    <td style={{ padding: '0.6rem 0.75rem', color: 'var(--text-secondary)', fontSize: '0.78rem' }}>
                      {app.location || '-'}
                    </td>
                    <td style={{ padding: '0.6rem 0.75rem', textAlign: 'center' }}>
                      <button
                        className="btn ghost-btn"
                        onClick={e => {
                          e.stopPropagation();
                          openEdit(app);
                        }}
                        style={{ padding: '0.25rem 0.5rem', fontSize: '0.75rem' }}
                      >
                        <i className="fa-solid fa-pen" />
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}

      {/* ---- Add/Edit Modal ---- */}
      {showAddModal && (
        <div
          style={{
            position: 'fixed',
            inset: 0,
            zIndex: 9000,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            background: 'rgba(0,0,0,0.6)',
            padding: '1rem',
          }}
          onClick={closeModal}
        >
          <div
            className="glass-panel"
            style={{
              maxWidth: '600px',
              width: '100%',
              maxHeight: '85vh',
              overflowY: 'auto',
              padding: '1.5rem',
            }}
            onClick={e => e.stopPropagation()}
          >
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1.25rem' }}>
              <h2 style={{ margin: 0, fontSize: '1.15rem', color: 'var(--text-primary)' }}>
                {editingApp ? 'Edit Application' : 'Add Application'}
              </h2>
              <button className="btn ghost-btn" onClick={closeModal} style={{ padding: '0.3rem 0.5rem', fontSize: '0.85rem' }}>
                <i className="fa-solid fa-xmark" />
              </button>
            </div>

            {/* Form fields */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
              {/* Company & Role — required */}
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem' }}>
                <div>
                  <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                    Company *
                  </label>
                  <input type="text" value={form.company} onChange={setField('company')} placeholder="e.g. Acme Inc" />
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                    Role *
                  </label>
                  <input type="text" value={form.role} onChange={setField('role')} placeholder="e.g. Senior Engineer" />
                </div>
              </div>

              {/* Status & Job URL */}
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem' }}>
                <div>
                  <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                    Status
                  </label>
                  <select value={form.status} onChange={setField('status')}>
                    {ALL_STATUSES.map(s => (
                      <option key={s} value={s}>
                        {s.charAt(0).toUpperCase() + s.slice(1)}
                      </option>
                    ))}
                  </select>
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                    Job URL
                  </label>
                  <input type="url" value={form.job_url} onChange={setField('job_url')} placeholder="https://..." />
                </div>
              </div>

              {/* Salary */}
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 100px', gap: '0.75rem' }}>
                <div>
                  <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                    Salary Min
                  </label>
                  <input type="number" value={form.salary_min} onChange={setField('salary_min')} placeholder="80000" />
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                    Salary Max
                  </label>
                  <input type="number" value={form.salary_max} onChange={setField('salary_max')} placeholder="120000" />
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                    Currency
                  </label>
                  <select value={form.salary_currency} onChange={setField('salary_currency')}>
                    <option value="USD">USD</option>
                    <option value="EUR">EUR</option>
                    <option value="GBP">GBP</option>
                    <option value="CAD">CAD</option>
                    <option value="AUD">AUD</option>
                  </select>
                </div>
              </div>

              {/* Location & remote */}
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem' }}>
                <div>
                  <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                    Location
                  </label>
                  <input type="text" value={form.location} onChange={setField('location')} placeholder="e.g. San Francisco, CA" />
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                    Work Type
                  </label>
                  <select value={form.remote_type} onChange={setField('remote_type')}>
                    {REMOTE_OPTIONS.map(opt => (
                      <option key={opt.value} value={opt.value}>{opt.label}</option>
                    ))}
                  </select>
                </div>
              </div>

              {/* Contact info */}
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '0.75rem' }}>
                <div>
                  <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                    Contact Name
                  </label>
                  <input type="text" value={form.contact_name} onChange={setField('contact_name')} placeholder="Recruiter name" />
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                    Contact Email
                  </label>
                  <input type="email" value={form.contact_email} onChange={setField('contact_email')} placeholder="recruiter@company.com" />
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                    Contact Title
                  </label>
                  <input type="text" value={form.contact_title} onChange={setField('contact_title')} placeholder="e.g. Senior Recruiter" />
                </div>
              </div>

              {/* Dates */}
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '0.75rem' }}>
                <div>
                  <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                    Date Applied
                  </label>
                  <input type="date" value={form.date_applied} onChange={setField('date_applied')} />
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                    Deadline
                  </label>
                  <input type="date" value={form.date_deadline} onChange={setField('date_deadline')} />
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                    Interview Date
                  </label>
                  <input type="date" value={form.date_interview} onChange={setField('date_interview')} />
                </div>
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem' }}>
                <div>
                  <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                    Offer Date
                  </label>
                  <input type="date" value={form.date_offer} onChange={setField('date_offer')} />
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                    Follow-up Date
                  </label>
                  <input type="date" value={form.date_follow_up} onChange={setField('date_follow_up')} />
                </div>
              </div>

              {/* Tags */}
              <div>
                <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                  Tags (comma-separated)
                </label>
                <input type="text" value={form.tags} onChange={setField('tags')} placeholder="e.g. frontend, react, startup" />
              </div>

              {/* Notes */}
              <div>
                <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                  Notes
                </label>
                <textarea
                  value={form.notes}
                  onChange={setField('notes')}
                  placeholder="Any notes about this application..."
                  rows={3}
                />
              </div>

              {/* Job URL link (when editing) */}
              {editingApp && form.job_url && (
                <a
                  href={form.job_url}
                  target="_blank"
                  rel="noopener noreferrer"
                  style={{ fontSize: '0.8rem', color: 'var(--primary-color)' }}
                >
                  <i className="fa-solid fa-external-link" style={{ marginRight: '0.3rem' }} />
                  Open job listing
                </a>
              )}
            </div>

            {/* Action buttons */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '1.5rem', gap: '0.5rem' }}>
              <div>
                {editingApp && (
                  confirmDelete === editingApp.id ? (
                    <div style={{ display: 'flex', gap: '0.4rem', alignItems: 'center' }}>
                      <span style={{ fontSize: '0.78rem', color: '#ef4444' }}>Delete?</span>
                      <button
                        className="btn ghost-btn"
                        onClick={() => handleDelete(editingApp.id)}
                        style={{ padding: '0.3rem 0.6rem', fontSize: '0.78rem', color: '#ef4444' }}
                      >
                        Yes
                      </button>
                      <button
                        className="btn ghost-btn"
                        onClick={() => setConfirmDelete(null)}
                        style={{ padding: '0.3rem 0.6rem', fontSize: '0.78rem' }}
                      >
                        No
                      </button>
                    </div>
                  ) : (
                    <button
                      className="btn ghost-btn"
                      onClick={() => setConfirmDelete(editingApp.id)}
                      style={{ padding: '0.3rem 0.6rem', fontSize: '0.78rem', color: '#ef4444' }}
                    >
                      <i className="fa-solid fa-trash" style={{ marginRight: '0.25rem' }} />
                      Delete
                    </button>
                  )
                )}
              </div>
              <div style={{ display: 'flex', gap: '0.5rem' }}>
                <button className="btn ghost-btn" onClick={closeModal}>
                  Cancel
                </button>
                <button
                  className="btn secondary-btn large-action-btn"
                  onClick={handleSave}
                  disabled={saving}
                >
                  {saving ? (
                    <>
                      <i className="fa-solid fa-spinner fa-spin" style={{ marginRight: '0.3rem' }} />
                      Saving...
                    </>
                  ) : (
                    <>
                      <i className="fa-solid fa-check" style={{ marginRight: '0.3rem' }} />
                      {editingApp ? 'Update' : 'Add Application'}
                    </>
                  )}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
