import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../context/SupabaseContext';

export interface JobApplication {
  id: string;
  user_id: string;
  company: string;
  role: string;
  status: JobApplicationStatus;
  job_url: string | null;
  salary_min: number | null;
  salary_max: number | null;
  salary_currency: string;
  location: string | null;
  remote_type: 'remote' | 'hybrid' | 'onsite' | null;
  contact_name: string | null;
  contact_email: string | null;
  contact_title: string | null;
  date_applied: string | null;
  date_deadline: string | null;
  date_interview: string | null;
  date_offer: string | null;
  date_follow_up: string | null;
  notes: string | null;
  tags: string[];
  generation_id: string | null;
  job_description: string | null;
  source: string;
  created_at: string;
  updated_at: string;
}

export type JobApplicationStatus =
  | 'saved'
  | 'applied'
  | 'screening'
  | 'interviewing'
  | 'offer'
  | 'rejected'
  | 'withdrawn';

export type JobApplicationInput = Omit<
  JobApplication,
  'id' | 'user_id' | 'created_at' | 'updated_at'
>;

export type JobApplicationUpdate = Partial<JobApplicationInput>;

export function useJobApplications() {
  const { user, supabase, isLoading: authLoading } = useAuth();
  const [applications, setApplications] = useState<JobApplication[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Fetch all applications for the current user
  const fetchApplications = useCallback(async () => {
    if (!user) {
      setApplications([]);
      setIsLoading(false);
      return;
    }

    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('job_applications')
        .select('*')
        .eq('user_id', user.id)
        .order('updated_at', { ascending: false });

      if (error) {
        console.error('Error fetching job applications:', error);
      } else {
        setApplications(data || []);
      }
    } finally {
      setIsLoading(false);
    }
  }, [user, supabase]);

  // Load on mount and when user changes
  useEffect(() => {
    if (authLoading) return;
    fetchApplications();
  }, [authLoading, fetchApplications]);

  // Add a new application
  const addApplication = useCallback(
    async (input: Partial<JobApplicationInput> & { company: string; role: string }) => {
      if (!user) return null;

      const row = {
        user_id: user.id,
        company: input.company,
        role: input.role,
        status: input.status || 'saved',
        job_url: input.job_url || null,
        salary_min: input.salary_min ?? null,
        salary_max: input.salary_max ?? null,
        salary_currency: input.salary_currency || 'USD',
        location: input.location || null,
        remote_type: input.remote_type || null,
        contact_name: input.contact_name || null,
        contact_email: input.contact_email || null,
        contact_title: input.contact_title || null,
        date_applied: input.date_applied || null,
        date_deadline: input.date_deadline || null,
        date_interview: input.date_interview || null,
        date_offer: input.date_offer || null,
        date_follow_up: input.date_follow_up || null,
        notes: input.notes || null,
        tags: input.tags || [],
        generation_id: input.generation_id || null,
        job_description: input.job_description || null,
        source: input.source || 'manual',
      };

      const { data, error } = await supabase
        .from('job_applications')
        .insert(row)
        .select()
        .single();

      if (error) {
        console.error('Error adding job application:', error);
        return null;
      }

      setApplications(prev => [data, ...prev]);
      return data as JobApplication;
    },
    [user, supabase],
  );

  // Update an existing application
  const updateApplication = useCallback(
    async (id: string, updates: JobApplicationUpdate) => {
      if (!user) return null;

      const { data, error } = await supabase
        .from('job_applications')
        .update(updates)
        .eq('id', id)
        .eq('user_id', user.id)
        .select()
        .single();

      if (error) {
        console.error('Error updating job application:', error);
        return null;
      }

      setApplications(prev =>
        prev.map(app => (app.id === id ? (data as JobApplication) : app)),
      );
      return data as JobApplication;
    },
    [user, supabase],
  );

  // Delete an application
  const deleteApplication = useCallback(
    async (id: string) => {
      if (!user) return false;

      const { error } = await supabase
        .from('job_applications')
        .delete()
        .eq('id', id)
        .eq('user_id', user.id);

      if (error) {
        console.error('Error deleting job application:', error);
        return false;
      }

      setApplications(prev => prev.filter(app => app.id !== id));
      return true;
    },
    [user, supabase],
  );

  // Filter applications by status
  const getByStatus = useCallback(
    (status: JobApplicationStatus) => {
      return applications.filter(app => app.status === status);
    },
    [applications],
  );

  return {
    applications,
    addApplication,
    updateApplication,
    deleteApplication,
    getByStatus,
    isLoading: isLoading || authLoading,
    refetch: fetchApplications,
  };
}
